import java.util.TreeSet;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        long total_substrings = n * (n + 1) / 2;
        TreeSet<Long> stars = new TreeSet<>();
        long no_star_substrings = total_substrings;
        for (int t = 0; t < n; t++) {
            long pos = order[t];
            Long left = stars.floor(pos);
            Long right = stars.ceil(pos);
            long left_val = (left == null) ? -1 : left;
            long right_val = (right == null) ? n : right;
            long previous_contribution = (right_val - left_val - 1) * (right_val - left_val) / 2;
            long part1 = (pos - left_val - 1) * (pos - left_val) / 2;
            long part2 = (right_val - pos - 1) * (right_val - pos) / 2;
            long new_contribution = part1 + part2;
            no_star_substrings -= (previous_contribution - new_contribution);
            stars.add(pos);
            long total_valid = total_substrings - no_star_substrings;
            if (total_valid >= k) {
                return t;
            }
        }
        return -1;
    }
}
